// TestCacheKey_Deterministic pins the cache-key contract: identical
// inputs must always produce the same output, even though Go's map
// range order is randomized. Regression for the cacheKey determinism
// fix — without sorting the param keys before hashing, two calls
// with the same params would produce different cache keys on a hot
// map, defeating the cache and inflating API call volume.
func TestCacheKey_Deterministic(t *testing.T) {
	c := &Client{}
	params := map[string]string{"a": "1", "b": "2", "c": "3", "d": "4"}

	// Same input must always produce the same output, even though
	// Go's map range order is randomized.
	first := c.cacheKey("/path", params)
	for i := 0; i < 100; i++ {
		got := c.cacheKey("/path", params)
		if got != first {
			t.Fatalf("cacheKey iteration %d = %q, want %q (must be deterministic across calls with identical input)", i, got, first)
		}
	}

	// Different param values must produce different keys.
	different := c.cacheKey("/path", map[string]string{"a": "1", "b": "2", "c": "3", "d": "5"})
	if different == first {
		t.Fatalf("cacheKey for differing param values matched first = %q (must change when a param value changes)", first)
	}

	// Different path must produce different key.
	diffPath := c.cacheKey("/other", params)
	if diffPath == first {
		t.Fatalf("cacheKey for differing path matched first = %q (must change when path changes)", first)
	}
}
